function createEnvWithEmptyWorkspace(): unknown {
  return {
    DB: {
      prepare() {
        return {
          bind() {
            return {
              async first() {
                return null;
              },
              async all() {
                return { results: [] };
              },
              async run() {
                return { success: true, meta: { changes: 0 } };
              },
            };
          },
        };
      },
    },
    Sandbox: {
      idFromName() {
        return {};
      },
      get() {
        return {};
      },
    },
  };
}

export async function runWorkspaceApiTests(): Promise<void> {
