                    return {
                      id: 'ws_reset_fail',
                      status: 'ready',
                      source_type: 'checkpoint',
                      checkpoint_id: '8a513f56ed70',
                      commit_sha: 'a'.repeat(40),
                      source_ref: 'main',
                      source_project_root: '.',
