                };
              },
            };
          }

          if (/UPDATE workspaces SET status = \?/i.test(sql)) {
            return {
              bind() {
                return {
                  async run() {
                    failedStatusUpdates += 1;
                    return { success: true, meta: { changes: 1 } };
                  },
                };
              },
            };
          }

          if (/UPDATE workspaces SET last_event_seq = last_event_seq \+ 1/i.test(sql)) {
            return {
              bind() {
